import Foundation

struct CategoryContent12 {
    static let aiUnderHood = CategoryData(
        id: "ai_under_hood", name: "How AI Thinks", icon: "gearshape.2", colorName: "aiOrange",
        description: "What happens inside AI, explained simply",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 11,
        unlockRequirement: .completeCategoryMinimum("ai_basics")
    )

    static let lesson1 = LessonData(id: "auh_l1", title: "What Is a Neural Network Really?", description: "Peek inside the wiring of an AI brain", categoryId: "ai_under_hood", questions: [
        Question(id: "auh1_q1", type: .multipleChoice, questionText: "In a neural network, what do 'weights' do?", options: ["They act like knobs that control how strongly one neuron influences another", "They measure how heavy the data files are on disk", "They count the total number of neurons in each layer", "They determine the physical size of the computer running the model"], correctAnswer: "They act like knobs that control how strongly one neuron influences another", explanation: "Weights are like volume knobs — turning them up makes a connection louder, turning them down makes it quieter. Training is all about finding the right knob settings."),
        Question(id: "auh1_q2", type: .trueFalse, questionText: "An activation function decides whether a neuron should 'fire' or stay silent, similar to a yes-or-no gate.", options: ["True", "False"], correctAnswer: "True", explanation: "Activation functions act like gatekeepers. They look at the incoming signal and decide whether to pass it forward or block it, giving the network the ability to make decisions."),
        Question(id: "auh1_q3", type: .fillInBlank, questionText: "In a neural network, data flows through multiple __________, each one transforming the information a little more before passing it on.", options: ["layers", "databases", "browsers", "cables"], correctAnswer: "layers", explanation: "Layers are like processing steps on an assembly line. Each layer takes the output of the previous one, transforms it, and passes the result forward toward the final answer."),
        Question(id: "auh1_q4", type: .sortOrder, questionText: "Put these steps of a neural network's forward pass in order:", options: ["Hidden layers transform the data", "The output layer produces a result", "Raw data enters the input layer", "Activation functions decide which signals pass through"], correctAnswers: ["Raw data enters the input layer", "Hidden layers transform the data", "Activation functions decide which signals pass through", "The output layer produces a result"], explanation: "Data flows in one direction: enter through the input, get transformed by hidden layers and activation functions, and finally produce a result at the output."),
        Question(id: "auh1_q5", type: .multipleChoice, questionText: "Why does a neural network need multiple layers instead of just one?", options: ["Each layer captures increasingly complex patterns, like building from edges to shapes to objects", "More layers make the code easier to read for programmers", "A single layer would use too much electricity", "Multiple layers are only used for decoration in architecture diagrams"], correctAnswer: "Each layer captures increasingly complex patterns, like building from edges to shapes to objects", explanation: "Early layers detect simple features like edges, middle layers combine them into shapes, and deep layers recognize complex concepts — like assembling a puzzle piece by piece."),
        Question(id: "auh1_q6", type: .scenarioJudgment, questionText: "Someone tells you a neural network is 'just a bunch of if-else statements.' Is this a fair description?", options: ["It captures the spirit of decision-making but misses the learning aspect", "Yes, that is exactly how neural networks work internally", "No, neural networks have nothing to do with decisions at all"], correctAnswer: "It captures the spirit of decision-making but misses the learning aspect", explanation: "Neurons do make threshold decisions like if-else gates, but the crucial difference is that a neural network learns its own rules from data rather than having a programmer write every condition by hand.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "auh_l2", title: "How Machines Learn", description: "Rolling downhill to find the right answer", categoryId: "ai_under_hood", questions: [
        Question(id: "auh2_q1", type: .multipleChoice, questionText: "Gradient descent is best described as:", options: ["Rolling a ball downhill to find the lowest point in a landscape of errors", "Sorting a list of numbers from largest to smallest", "Compressing files to save storage space", "Randomly guessing answers until one works"], correctAnswer: "Rolling a ball downhill to find the lowest point in a landscape of errors", explanation: "Imagine a hilly landscape where lower means fewer errors. Gradient descent rolls a ball downhill step by step, always moving toward the lowest valley — the best set of weights."),
        Question(id: "auh2_q2", type: .trueFalse, questionText: "A loss function measures how wrong the model's predictions are compared to the correct answers.", options: ["True", "False"], correctAnswer: "True", explanation: "The loss function is like a scorecard that asks 'how wrong am I?' after every prediction. A high loss means the model is way off; a low loss means it is getting close."),
        Question(id: "auh2_q3", type: .fillInBlank, questionText: "The __________ controls how big each step is when the model adjusts its weights during training.", options: ["learning rate", "batch size", "layer count", "activation type"], correctAnswer: "learning rate", explanation: "The learning rate is like choosing your stride length when walking downhill. Too big and you overshoot the valley; too small and you take forever to get there."),
        Question(id: "auh2_q4", type: .matchPairs, questionText: "Match each training concept with its plain-English meaning:", matchPairs: [
            MatchPair(term: "Gradient Descent", definition: "Rolling downhill to reduce errors"),
            MatchPair(term: "Loss Function", definition: "Scorecard measuring how wrong you are"),
            MatchPair(term: "Learning Rate", definition: "Size of each adjustment step"),
            MatchPair(term: "Backpropagation", definition: "Sending error signals backward to fix weights")
        ], explanation: "These four concepts form the core learning loop: measure the error, figure out which weights caused it, and nudge them in the right direction."),
        Question(id: "auh2_q5", type: .multipleChoice, questionText: "What happens if the learning rate is set too high?", options: ["The model overshoots the best answer and bounces around without converging", "The model trains more slowly but always finds the perfect answer", "The model automatically switches to a better algorithm", "The model runs out of memory and crashes"], correctAnswer: "The model overshoots the best answer and bounces around without converging", explanation: "A learning rate that is too high is like taking giant leaps on a mountainside — you jump right over the valley floor and land on the other side, never settling down."),
        Question(id: "auh2_q6", type: .multipleChoice, questionText: "Backpropagation works by:", options: ["Tracing errors backward through the network to figure out which weights to adjust", "Feeding data through the network a second time in reverse order", "Deleting neurons that made wrong predictions", "Copying the correct answers directly into the weights"], correctAnswer: "Tracing errors backward through the network to figure out which weights to adjust", explanation: "Backpropagation sends blame backward from the output to the input, telling each weight how much it contributed to the error so it knows how much to change.")
    ], order: 1, difficulty: .intermediate)

    static let lesson3 = LessonData(id: "auh_l3", title: "The Attention Mechanism", description: "How transformers decide what matters", categoryId: "ai_under_hood", questions: [
        Question(id: "auh3_q1", type: .multipleChoice, questionText: "In a transformer model, 'self-attention' allows the model to:", options: ["Decide which words in a sentence are most relevant to each other", "Pay attention to the user's webcam to read facial expressions", "Focus only on the first and last word of every sentence", "Automatically correct spelling errors before processing"], correctAnswer: "Decide which words in a sentence are most relevant to each other", explanation: "Self-attention lets every word look at every other word in the sentence and decide which ones are important for understanding its meaning, like highlighting the key parts of a paragraph."),
        Question(id: "auh3_q2", type: .trueFalse, questionText: "The famous AI research paper 'Attention Is All You Need' introduced the transformer architecture that powers models like Claude, GPT, and Gemini.", options: ["True", "False"], correctAnswer: "True", explanation: "Published by Google researchers in 2017, this landmark paper showed that attention mechanisms alone — without older techniques like recurrence — could achieve state-of-the-art results, revolutionizing AI."),
        Question(id: "auh3_q3", type: .matchPairs, questionText: "Match each attention concept to its analogy:", matchPairs: [
            MatchPair(term: "Query", definition: "The question you are asking"),
            MatchPair(term: "Key", definition: "A label describing what information is available"),
            MatchPair(term: "Value", definition: "The actual content you retrieve"),
            MatchPair(term: "Attention Score", definition: "How relevant a piece of information is to your question")
        ], explanation: "Think of it like a library: the query is your research question, keys are book titles on the shelf, values are the book contents, and the attention score tells you which books are most relevant."),
        Question(id: "auh3_q4", type: .fillInBlank, questionText: "Before transformers, models processed language one word at a time in sequence, but transformers can process all words in __________.", options: ["parallel", "reverse", "alphabetical order", "pairs"], correctAnswer: "parallel", explanation: "This is a superpower of transformers. Instead of reading a sentence word by word like older models, they see all words at once and figure out relationships in parallel, making them much faster to train."),
        Question(id: "auh3_q5", type: .scenarioJudgment, questionText: "In the sentence 'The cat sat on the mat because it was tired,' a transformer needs to figure out that 'it' refers to 'the cat.' Which mechanism helps most?", options: ["Self-attention, because it lets the model compare every word with every other word", "The input layer, because it reads the sentence first", "The loss function, because it measures errors"], correctAnswer: "Self-attention, because it lets the model compare every word with every other word", explanation: "Self-attention allows the model to compute a high relevance score between 'it' and 'cat,' correctly resolving the reference. This ability to connect distant words is what makes transformers so powerful."),
        Question(id: "auh3_q6", type: .multipleChoice, questionText: "Why do transformers use 'multi-head' attention instead of a single attention mechanism?", options: ["Different heads can focus on different types of relationships simultaneously", "Multiple heads use less memory than a single head", "It is a branding decision with no technical benefit", "Each head processes a different language"], correctAnswer: "Different heads can focus on different types of relationships simultaneously", explanation: "Multi-head attention is like having several experts each looking at the sentence from a different angle — one might focus on grammar, another on meaning, another on word proximity — then combining their insights.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "auh_l4", title: "Probability & Prediction", description: "How AI picks its next word", categoryId: "ai_under_hood", questions: [
        Question(id: "auh4_q1", type: .multipleChoice, questionText: "Large language models generate text by:", options: ["Predicting the most likely next token based on everything that came before", "Looking up pre-written responses in a database", "Copying and pasting from web pages in real time", "Running a grammar checker and filling in blanks"], correctAnswer: "Predicting the most likely next token based on everything that came before", explanation: "At its core, a language model is a next-token prediction engine. Given a sequence of words, it calculates the probability of every possible next word and picks one."),
        Question(id: "auh4_q2", type: .fillInBlank, questionText: "The __________ setting acts like a creativity dial: low values make the model more predictable, and high values make it more random and surprising.", options: ["temperature", "volume", "brightness", "frequency"], correctAnswer: "temperature", explanation: "Temperature controls how spread out the probability distribution is. At low temperature, the model almost always picks the highest-probability word. At high temperature, it is more willing to take creative risks."),
        Question(id: "auh4_q3", type: .trueFalse, questionText: "AI 'hallucinations' happen because the model is confidently predicting tokens that sound right but are factually wrong.", options: ["True", "False"], correctAnswer: "True", explanation: "Language models optimize for what sounds probable, not what is true. When the most likely next token happens to be incorrect, the model states falsehoods with full confidence — this is called hallucination."),
        Question(id: "auh4_q4", type: .matchPairs, questionText: "Match each sampling concept to what it controls:", matchPairs: [
            MatchPair(term: "Temperature", definition: "How creative or conservative the output is"),
            MatchPair(term: "Top-k sampling", definition: "Only consider the k most likely next words"),
            MatchPair(term: "Top-p sampling", definition: "Only consider words whose probabilities add up to p"),
            MatchPair(term: "Softmax", definition: "Converts raw scores into probabilities that sum to one")
        ], explanation: "These sampling strategies give developers fine-grained control over the randomness and quality of AI-generated text, balancing creativity with coherence."),
        Question(id: "auh4_q5", type: .multipleChoice, questionText: "What does the softmax function do in a language model?", options: ["It turns a list of raw scores into probabilities that add up to one, highlighting the most likely option", "It makes the model run faster by compressing the output", "It filters out offensive words before they appear in the response", "It sorts the vocabulary in alphabetical order"], correctAnswer: "It turns a list of raw scores into probabilities that add up to one, highlighting the most likely option", explanation: "Softmax is like a voting system that takes raw popularity scores and converts them into clean percentages. The highest-scoring option gets the biggest share of probability."),
        Question(id: "auh4_q6", type: .scenarioJudgment, questionText: "You are using an AI to write a creative short story. Should you set the temperature high or low?", options: ["High, to encourage more creative and unexpected word choices", "Low, because stories must be factually accurate above all else", "Temperature has no effect on creative writing tasks"], correctAnswer: "High, to encourage more creative and unexpected word choices", explanation: "A higher temperature lets the model explore less obvious word choices, producing more imaginative and surprising prose. For factual tasks you would lower the temperature to keep the model on track.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "auh_l5", title: "Embeddings & Similarity", description: "How AI understands what words mean", categoryId: "ai_under_hood", questions: [
        Question(id: "auh5_q1", type: .multipleChoice, questionText: "An 'embedding' in AI is best described as:", options: ["A list of numbers that captures the meaning of a word or concept in a way computers can process", "A watermark hidden inside AI-generated images", "A physical chip embedded in the server hardware", "A compressed copy of the entire training dataset"], correctAnswer: "A list of numbers that captures the meaning of a word or concept in a way computers can process", explanation: "Embeddings translate human concepts into numerical coordinates in a high-dimensional space. Words with similar meanings end up close together, letting the model reason about meaning using math."),
        Question(id: "auh5_q2", type: .trueFalse, questionText: "In embedding space, the famous analogy 'king minus man plus woman equals queen' shows that vector arithmetic can capture real-world relationships between concepts.", options: ["True", "False"], correctAnswer: "True", explanation: "This classic example demonstrates that embeddings encode relationships as directions in space. The direction from 'man' to 'woman' is similar to the direction from 'king' to 'queen,' showing that meaning has geometric structure."),
        Question(id: "auh5_q3", type: .fillInBlank, questionText: "__________ similarity measures how close two vectors are by looking at the angle between them, and it is widely used in semantic search.", options: ["Cosine", "Tangent", "Diameter", "Pixel"], correctAnswer: "Cosine", explanation: "Cosine similarity looks at the angle between two embedding vectors. If they point in nearly the same direction, the concepts are similar. It ignores length and focuses purely on direction."),
        Question(id: "auh5_q4", type: .multipleChoice, questionText: "Why are similar concepts placed close together in embedding space?", options: ["Because words that appear in similar contexts end up with similar numerical representations during training", "Because a human librarian manually arranges them by topic", "Because the alphabet naturally groups related words near each other", "Because the model memorizes a dictionary of synonyms"], correctAnswer: "Because words that appear in similar contexts end up with similar numerical representations during training", explanation: "The model learns from context: since 'happy' and 'joyful' appear in similar sentences, training pushes their embeddings close together. The meaning emerges from usage patterns, not from a dictionary."),
        Question(id: "auh5_q5", type: .sortOrder, questionText: "Put these steps of semantic search in order:", options: ["Return the documents whose embeddings are closest to the query", "Convert the user's search query into an embedding", "Convert all documents into embeddings ahead of time", "Compare the query embedding against every document embedding"], correctAnswers: ["Convert all documents into embeddings ahead of time", "Convert the user's search query into an embedding", "Compare the query embedding against every document embedding", "Return the documents whose embeddings are closest to the query"], explanation: "Semantic search first pre-computes document embeddings, then at search time converts the query, compares it against all documents, and returns the closest matches — finding meaning, not just keywords."),
        Question(id: "auh5_q6", type: .scenarioJudgment, questionText: "A search engine using keyword matching fails to find a relevant article about 'automobiles' when the user searches for 'cars.' Would switching to embedding-based search help?", options: ["Yes, because embeddings understand that 'cars' and 'automobiles' mean the same thing", "No, because embeddings only work with exact word matches", "It depends on the color scheme of the search interface"], correctAnswer: "Yes, because embeddings understand that 'cars' and 'automobiles' mean the same thing", explanation: "Embedding-based search matches by meaning, not by exact keywords. Since 'cars' and 'automobiles' have nearly identical embeddings, the search would find the article even though the exact word differs.")
    ], order: 4, difficulty: .advanced)

    static let lesson6 = LessonData(id: "auh_l6", title: "Training at Scale", description: "Why building a frontier model costs millions", categoryId: "ai_under_hood", questions: [
        Question(id: "auh6_q1", type: .multipleChoice, questionText: "Why does training a large AI model cost millions of dollars?", options: ["It requires thousands of specialized GPUs running for weeks or months, consuming enormous amounts of electricity", "The training data must be purchased from a single expensive vendor", "AI researchers demand extremely high salaries that inflate the budget", "The software licenses for neural networks are priced per neuron"], correctAnswer: "It requires thousands of specialized GPUs running for weeks or months, consuming enormous amounts of electricity", explanation: "Training frontier models like Claude or GPT requires massive GPU clusters running around the clock. The electricity, hardware, and cooling costs add up to tens or even hundreds of millions of dollars."),
        Question(id: "auh6_q2", type: .trueFalse, questionText: "Distributed training splits the work of training a model across many GPUs so they can work in parallel.", options: ["True", "False"], correctAnswer: "True", explanation: "A single GPU cannot hold or process an entire frontier model. Distributed training divides the model and data across hundreds or thousands of GPUs that coordinate with each other to train as one system."),
        Question(id: "auh6_q3", type: .fillInBlank, questionText: "__________ laws describe the predictable relationship between model size, data amount, compute budget, and the resulting model performance.", options: ["Scaling", "Privacy", "Copyright", "Gravity"], correctAnswer: "Scaling", explanation: "Scaling laws, discovered by researchers at OpenAI and later refined by others, show that model performance improves predictably as you increase compute, data, and parameters — helping labs plan how to spend their training budgets."),
        Question(id: "auh6_q4", type: .matchPairs, questionText: "Match each training-at-scale concept to its meaning:", matchPairs: [
            MatchPair(term: "Data Pipeline", definition: "System that collects, cleans, and feeds data to the model"),
            MatchPair(term: "Distributed Training", definition: "Splitting work across many GPUs"),
            MatchPair(term: "Compute Budget", definition: "Total processing power allocated for training"),
            MatchPair(term: "Chinchilla Optimal", definition: "Ideal balance of model size and training data")
        ], explanation: "Building a frontier model requires orchestrating data, hardware, and budget. The Chinchilla research from Google DeepMind showed that many earlier models were undertrained — they needed more data relative to their size."),
        Question(id: "auh6_q5", type: .multipleChoice, questionText: "The 'Chinchilla optimal' research finding showed that:", options: ["Many large models were undertrained and would perform better with more data and fewer parameters", "Smaller models always outperform larger ones regardless of data", "Training should always be done on a single very powerful GPU", "The best models are trained exclusively on data from encyclopedias"], correctAnswer: "Many large models were undertrained and would perform better with more data and fewer parameters", explanation: "Google DeepMind's Chinchilla paper revealed that the optimal strategy is to balance model size with the amount of training data. A smaller model trained on more data can outperform a larger model trained on less."),
        Question(id: "auh6_q6", type: .sortOrder, questionText: "Put these steps of a large-scale training pipeline in order:", options: ["Deploy the trained model for users", "Evaluate the model on benchmark tests", "Collect and clean massive datasets", "Train the model across a GPU cluster for weeks"], correctAnswers: ["Collect and clean massive datasets", "Train the model across a GPU cluster for weeks", "Evaluate the model on benchmark tests", "Deploy the trained model for users"], explanation: "Building a frontier model follows a pipeline: first gather and prepare high-quality data, then train across a massive compute cluster, evaluate performance on benchmarks, and finally deploy the model for real-world use.")
    ], order: 5, difficulty: .advanced)
}
